import { prisma } from "@/lib/prisma";
import Link from "next/link";
import { UploadCloud, Folder, Activity, ArrowRight, Sparkles, Building2, UserCircle } from "lucide-react";
import DeleteProjectButton from "@/components/DeleteProjectButton";
import EEGLogo from "@/components/EEGLogo";
import T from "@/components/T";
import LanguageSwitcher from "@/components/LanguageSwitcher";

export const dynamic = 'force-dynamic';

export default async function PMDashboard() {
    const pmEmail = "pm@worksite.com";
    const user = await prisma.user.findUnique({
        where: { email: pmEmail },
        include: {
            projectsAsPM: {
                include: {
                    weeklyPlans: true,
                    siteManager: true,
                    tasks: true,
                    revisions: {
                        orderBy: { uploadedAt: 'desc' }
                    }
                },
            },
        },
    });

    if (!user) return <div>Utilisateur introuvable</div>;

    const totalPlans = user.projectsAsPM.reduce((acc, proj) => acc + proj.weeklyPlans.length, 0);

    return (
        <div className="min-h-screen bg-[#050810] text-white font-sans selection:bg-purple-500/30">
            {/* Background Glows */}
            <div className="fixed top-0 right-0 w-[40vw] h-[40vw] bg-purple-900/10 rounded-full blur-[150px] pointer-events-none" />
            <div className="fixed bottom-0 left-0 w-[50vw] h-[50vw] bg-cyan-900/10 rounded-full blur-[150px] pointer-events-none" />

            <nav className="sticky top-0 z-50 w-full px-4 sm:px-8 py-4 flex items-center justify-between border-b border-white/5 bg-[#050810]/80 backdrop-blur-xl shadow-[0_4px_30px_rgba(0,0,0,0.5)]">
                <Link href="/" className="flex items-center gap-3 group">
                    <EEGLogo className="w-8 h-8 text-purple-400 drop-shadow-[0_0_15px_rgba(168,85,247,0.6)] group-hover:scale-110 transition-transform" />
                    <span className="hidden sm:inline-block text-xl font-black tracking-tighter text-white drop-shadow-md">
                        EEG <span className="text-purple-400 font-light">Management</span>
                    </span>
                </Link>
                <div className="flex items-center gap-4 sm:gap-6">
                    <LanguageSwitcher />
                    <div className="flex items-center gap-3 pl-4 sm:pl-6 border-l border-white/10">
                        <div className="hidden sm:flex flex-col items-end">
                            <span className="text-sm font-bold">{user.name}</span>
                            <span className="text-xs text-purple-400 font-medium tracking-wider uppercase">Chef de Projet</span>
                        </div>
                        <UserCircle size={36} className="text-gray-400 drop-shadow-[0_0_15px_rgba(255,255,255,0.2)]" />
                    </div>
                </div>
            </nav>

            <main className="max-w-[1200px] mx-auto px-4 sm:px-8 py-8 sm:py-12 relative z-10 flex flex-col gap-10">
                
                {/* Hero Section */}
                <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
                    <div>
                        <div className="flex items-center gap-2 mb-3">
                            <Sparkles size={18} className="text-purple-400 drop-shadow-[0_0_10px_rgba(168,85,247,0.8)]" />
                            <span className="text-purple-400 font-bold tracking-widest uppercase text-xs sm:text-sm"><T k="special_works" /></span>
                        </div>
                        <h1 className="text-4xl sm:text-5xl font-black tracking-tight text-transparent bg-clip-text bg-gradient-to-r from-white via-purple-100 to-purple-400 mb-2">
                            <T k="dashboard" />
                        </h1>
                        <p className="text-gray-400 text-lg max-w-xl">Supervision de l&apos;ensemble des installations, des équipes sur site et suivis budgétaires.</p>
                    </div>
                    <div className="flex flex-wrap gap-4 w-full md:w-auto">
                        <Link href="/pm/analytics" className="flex items-center justify-center gap-2 px-6 py-3 rounded-full bg-white/5 hover:bg-white/10 border border-white/10 font-bold text-white transition-all hover:shadow-[0_0_20px_rgba(255,255,255,0.1)] w-full sm:w-auto">
                            <Activity size={18} /> Voir les Analyses
                        </Link>
                        <Link href="/pm/upload" className="flex items-center justify-center gap-2 px-6 py-3 rounded-full bg-gradient-to-r from-purple-600 to-blue-500 font-bold text-white shadow-[0_0_20px_rgba(147,51,234,0.4)] hover:shadow-[0_0_30px_rgba(59,130,246,0.6)] transition-all hover:scale-[1.02] w-full sm:w-auto">
                            <UploadCloud size={18} /> Téléverser Plan XLS
                        </Link>
                    </div>
                </div>

                {/* KPI Cards */}
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                    <div className="glass-card flex items-center justify-between p-8 bg-[#080d1a]/80 backdrop-blur-md rounded-[32px] border border-white/5 shadow-[0_10px_40px_rgba(0,0,0,0.5)] relative overflow-hidden group hover:border-purple-500/30 transition-all">
                        <div className="absolute top-0 right-0 w-32 h-32 bg-purple-500/10 rounded-bl-[100px] -z-10 group-hover:scale-110 transition-transform" />
                        <div>
                            <h4 className="flex items-center gap-2 mb-2 text-gray-400 font-bold uppercase tracking-widest text-sm"><Folder size={18} className="text-purple-400" /> <T k="active_projects" /></h4>
                            <div className="text-5xl font-black text-white drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]">{user.projectsAsPM.length}</div>
                        </div>
                    </div>
                    <div className="glass-card flex items-center justify-between p-8 bg-[#080d1a]/80 backdrop-blur-md rounded-[32px] border border-white/5 shadow-[0_10px_40px_rgba(0,0,0,0.5)] relative overflow-hidden group hover:border-blue-500/30 transition-all">
                        <div className="absolute top-0 right-0 w-32 h-32 bg-blue-500/10 rounded-bl-[100px] -z-10 group-hover:scale-110 transition-transform" />
                        <div>
                            <h4 className="flex items-center gap-2 mb-2 text-gray-400 font-bold uppercase tracking-widest text-sm"><Activity size={18} className="text-blue-400" /> <T k="submitted_plans" /></h4>
                            <div className="text-5xl font-black text-white drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]">{totalPlans}</div>
                        </div>
                    </div>
                </div>

                {/* Projects List */}
                <section>
                    <h3 className="text-2xl font-bold mb-6 flex items-center gap-3">
                        <Building2 className="text-purple-400" /> <T k="your_sites" />
                    </h3>
                    
                    <div className="flex flex-col gap-6">
                        {user.projectsAsPM.map((proj: any) => (
                            <div key={proj.id} className="relative glass-card bg-[#0a1020]/90 backdrop-blur-xl border border-white/10 rounded-[32px] p-6 sm:p-8 shadow-[0_20px_50px_rgba(0,0,0,0.5)] hover:border-purple-500/30 transition-all duration-300 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                                
                                <div className="flex-1">
                                    <h3 className="text-2xl font-black text-white mb-3">{proj.name}</h3>
                                    
                                    <div className="flex flex-wrap gap-2 mb-4">
                                        <span className="px-3 py-1 rounded-full bg-white/5 border border-white/10 text-xs font-bold text-gray-300">
                                            <T k="site_manager" />: <span className="text-purple-300">{proj.siteManager?.name || 'Non assigné'}</span>
                                        </span>
                                        <span className="px-3 py-1 rounded-full bg-white/5 border border-white/10 text-xs font-bold text-gray-300">
                                            <T k="location" />: {proj.location || 'N/A'}
                                        </span>
                                        <span className="px-3 py-1 rounded-full bg-white/5 border border-white/10 text-xs font-bold text-gray-300">
                                            <T k="tasks_loaded" />: <span className="text-blue-300">{proj.tasks.length}</span>
                                        </span>
                                    </div>

                                    <div className="flex flex-col sm:flex-row gap-3">
                                        {proj.revisions && proj.revisions.length > 0 && (
                                            <div className="text-xs bg-purple-900/20 px-3 py-2 rounded-lg border border-purple-500/30">
                                                <strong className="text-purple-300"><T k="last_revision" />:</strong> {new Date(proj.revisions[0].uploadedAt).toLocaleDateString()} 
                                            </div>
                                        )}
                                        {(() => {
                                            const totalDrums = proj.weeklyPlans?.reduce((sum: number, wp: { emptyDrumsCount?: number | null }) => sum + (wp.emptyDrumsCount || 0), 0) || 0;
                                            if (totalDrums > 0) {
                                                return (
                                                    <div className="text-xs bg-orange-900/20 px-3 py-2 rounded-lg border border-orange-500/30 text-orange-200">
                                                        <strong><T k="empty_drums" /> :</strong> {totalDrums} alertes
                                                    </div>
                                                );
                                            }
                                            return null;
                                        })()}
                                    </div>
                                </div>
                                
                                <div className="flex flex-row md:flex-col gap-3 w-full md:w-auto mt-4 md:mt-0">
                                    <Link href={`/pm/project/${proj.id}`} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-3 rounded-full bg-white/10 hover:bg-white/20 text-white font-bold transition-all shadow-md text-sm">
                                        <T k="view_details" /> <ArrowRight size={16} />
                                    </Link>
                                    <DeleteProjectButton projectId={proj.id} projectName={proj.name} />
                                </div>
                            </div>
                        ))}
                        {user.projectsAsPM.length === 0 && (
                            <div className="glass-card bg-[#0a1020]/90 border border-white/5 text-center py-20 text-gray-400 rounded-[32px]">
                                <T k="no_projects" />
                            </div>
                        )}
                    </div>
                </section>
            </main>
        </div>
    );
}

"use client";

import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, TooltipProps } from 'recharts';
import { Project, WeeklyPlan, Task, WeeklyPlanTask } from '@prisma/client';

interface ExtendedWeeklyPlanTask extends WeeklyPlanTask {
    task: Task;
}

interface ExtendedWeeklyPlan extends WeeklyPlan {
    tasks: ExtendedWeeklyPlanTask[];
}

interface ExtendedProject extends Project {
    weeklyPlans: ExtendedWeeklyPlan[];
}

interface CategoryData {
    name: string;
    efficiency: number;
    planned: number;
    executed: number;
}

export default function GlobalCategoryAnalytics({ projects }: { projects: ExtendedProject[] }) {
    const heatmapData = useMemo(() => {
        const catMap: Record<string, { planned: number, executed: number }> = {};
        
        projects.forEach(proj => {
            proj.weeklyPlans.forEach(plan => {
                plan.tasks.forEach(pt => {
                    const cat = pt.task?.category || "Autre";
                    const minsPerUnit = pt.task?.minutesPerUnit || 0;
                    
                    if (!catMap[cat]) catMap[cat] = { planned: 0, executed: 0 };
                    catMap[cat].planned += (pt.plannedQuantity * minsPerUnit) / 60;
                    catMap[cat].executed += (pt.actualQuantity * minsPerUnit) / 60;
                });
            });
        });

        return Object.entries(catMap)
            .map(([name, data]) => {
                const efficiency = data.planned > 0 ? (data.executed / data.planned) * 100 : 0;
                return {
                    name,
                    efficiency: Number(efficiency.toFixed(1)),
                    planned: Number(data.planned.toFixed(1)),
                    executed: Number(data.executed.toFixed(1)),
                } as CategoryData;
            })
            .filter(item => item.planned > 0 || item.executed > 0)
            .sort((a, b) => b.planned - a.planned);
    }, [projects]);

    const getEfficiencyColor = (efficiency: number) => {
        if (efficiency < 70) return '#ef4444'; // Red
        if (efficiency < 90) return '#f59e0b'; // Amber
        return '#10b981'; // Green
    };

    return (
        <div className="w-full h-[400px]">
            <ResponsiveContainer width="100%" height="100%">
                <BarChart data={heatmapData} margin={{ top: 20, right: 30, left: 0, bottom: 20 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.1)" vertical={false} />
                    <XAxis dataKey="name" stroke="#94a3b8" tick={{fontSize: 12}} />
                    <YAxis stroke="#94a3b8" unit="%" />
                    <Tooltip
                        contentStyle={{ backgroundColor: '#161920', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '8px' }}
                        itemStyle={{ color: '#fff' }}
                        cursor={{ fill: 'rgba(255,255,255,0.05)' }}
                        formatter={(value: number, name: string) => {
                            if (name === 'efficiency') return [`${value}%`, 'Efficacité'];
                            return [value, name];
                        }}
                    />
                    <Bar dataKey="efficiency" radius={[4, 4, 0, 0]}>
                        {heatmapData.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={getEfficiencyColor(entry.efficiency)} />
                        ))}
                    </Bar>
                </BarChart>
            </ResponsiveContainer>
        </div>
    );
}
